head.script:
scwin.gv_rowPos6 = 0;
scwin.gv_rowPos7 = 0;
scwin.txt_wrkIndictNo = "";
scwin.txt_hveqDuseCnt = "";
scwin.txt_hcvsslMgntNo = "";
scwin.txt_hwrkDt = "";
