scwin.sbm_combo1_submitdone = function(e) {
    if (co_ds_combo1.getRowCount() > 0) {
        $c.gus.cfEnableObj(lux_wrkIndictNo, true);
        $c.gus.cfEnableObj(button_no1, true);
    } else {
        $c.gus.cfEnableObj(lux_wrkIndictNo, false);
        $c.gus.cfEnableObj(button_no1, false);
    }
    if (parent.ds_main2.getRowCount() > 0) {
        if (parent.ds_main2.getCellData(0, "completeProcYn") == 1) {
            $c.gus.cfEnableObj(button_no1, false);
        } else {
            $c.gus.cfEnableObj(button_no1, true);
        }
    }
};

